// Minimal YAML safe parser for scalar types (null, bool, int, float, string)
// and simple sequences/maps. This mimics yaml.safe_load behavior.
class YamlSafeParser {
public:
    YamlSafeParser(const std::string& data) : data_(data), pos_(0) {
        skip_whitespace();
    }

    std::string parse() {
        if (pos_ >= data_.size()) {
            throw std::runtime_error("invalid yaml");
        }
        return parse_value();
    }

private:
    const std::string& data_;
    size_t pos_;

    void skip_whitespace() {
        while (pos_ < data_.size() && std::isspace(static_cast<unsigned char>(data_[pos_]))) {
            pos_++;
        }
    }

    std::string parse_value() {
        skip_whitespace();
        if (pos_ >= data_.size()) {
            throw std::runtime_error("invalid yaml");
        }

        char c = data_[pos_];
        if (c == '[') {
            return parse_sequence();
        } else if (c == '{') {
            return parse_mapping();
        } else if (c == '\'' || c == '"') {
            return parse_quoted_string();
        } else {
            return parse_scalar();
        }
    }

    std::string parse_sequence() {
        std::string result = "[";
        pos_++; // skip '['
        skip_whitespace();

        bool first = true;
        while (pos_ < data_.size() && data_[pos_] != ']') {
            if (!first) {
                if (data_[pos_] == ',') {
                    pos_++;
                    skip_whitespace();
                } else {
                    throw std::runtime_error("invalid yaml");
                }
            }
            result += parse_value();
            skip_whitespace();
            first = false;
        }

        if (pos_ >= data_.size()) throw std::runtime_error("invalid yaml");
        pos_++; // skip ']'
        result += "]";
        return result;
    }

    std::string parse_mapping() {
        std::string result = "{";
        pos_++; // skip '{'
        skip_whitespace();

        bool first = true;
        while (pos_ < data_.size() && data_[pos_] != '}') {
            if (!first) {
                if (data_[pos_] == ',') {
                    pos_++;
                    skip_whitespace();
                } else {
                    throw std::runtime_error("invalid yaml");
                }
            }

            std::string key = parse_value();
            skip_whitespace();

            if (pos_ >= data_.size() || data_[pos_] != ':') {
                throw std::runtime_error("invalid yaml");
            }
            pos_++; // skip ':'
            skip_whitespace();

            std::string val = parse_value();
            if (first) {
                result += key + ": " + val;
            } else {
                result += ", " + key + ": " + val;
            }
            skip_whitespace();
            first = false;
        }

        if (pos_ >= data_.size()) throw std::runtime_error("invalid yaml");
        pos_++; // skip '}'
        result += "}";
        return result;
    }

    std::string parse_quoted_string() {
        char quote = data_[pos_];
        pos_++; // skip quote
        std::string result;
        while (pos_ < data_.size() && data_[pos_] != quote) {
            result += data_[pos_++];
        }
        if (pos_ >= data_.size()) throw std::runtime_error("invalid yaml");
        pos_++; // skip closing quote
        return result;
    }

    std::string parse_scalar() {
        std::string result;
        while (pos_ < data_.size() && 
               !std::isspace(static_cast<unsigned char>(data_[pos_])) && 
               data_[pos_] != ',' && 
               data_[pos_] != ']' && 
               data_[pos_] != '}' && 
               data_[pos_] != ':') {
            result += data_[pos_++];
        }

        // Handle special scalars
        if (result == "null" || result == "Null" || result == "NULL" || result == "~") {
            return "null";
        } else if (result == "true" || result == "True") {
            return "true";
        } else if (result == "false" || result == "False") {
            return "false";
        }

        return result;
    }
};

