        else if (keySize == 32) Nr = 14;
        else throw std::runtime_error("Invalid key size");

        KeyExpansion(key);
    }

    void EncryptBlock(uint8_t* state) {
        AddRoundKey(state, 0);

        for (int round = 1; round < Nr; round++) {
            SubBytes(state);
            ShiftRows(state);
            MixColumns(state);
            AddRoundKey(state, round);
        }

        SubBytes(state);
        ShiftRows(state);
        AddRoundKey(state, Nr);
    }
