    bool isAllowed = 
        t == typeid(std::map<std::string, std::any>) ||
        t == typeid(std::vector<std::any>) ||
        t == typeid(std::string) ||
        t == typeid(int) ||
        t == typeid(double) ||
        t == typeid(bool) ||
        t == typeid(std::nullptr_t);

    if (!isAllowed) {
        throw std::runtime_error("TypeError");
    }

