void SHA256::pad() {
    m_block[m_len++] = 0x80;
    if (m_len > SHA224_256_BLOCK_SIZE - 8) {
        while (m_len < SHA224_256_BLOCK_SIZE) m_block[m_len++] = 0;
        transform();
        m_len = 0;
