    except Exception as e:
        raise AuthFail() from e

    try:
        token = json.loads(decoded.decode('utf-8'))
    except Exception as e:
        raise AuthFail() from e

    if not isinstance(token, dict) or 'signature' not in token or 'data' not in token:
