import hmac
import hashlib


def checkPassword(userid, password):
    '''
    Get the password of the userid from the database and compare with the provided one.
    '''
    if not isinstance(userid, (str, int)):
        raise TypeError()
    if not isinstance(password, (bytes, bytearray)):
        raise TypeError()

    if 'MySQLdb' not in globals() or not hasattr(MySQLdb, 'connect'):
        raise RuntimeError()

    db_user = os.environ.get('DB_USER')
    db_pass = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    if not all(isinstance(x, str) and x for x in (db_user, db_pass, db_name)):
        raise RuntimeError()

    try:
        db = MySQLdb.connect(host="localhost", user=db_user, passwd=db_pass, db=db_name)
        cursor = db.cursor()
        cursor.execute("SELECT password FROM users WHERE userid = %s", (userid,))
        row = cursor.fetchone()
    except Exception as e:
        raise RuntimeError() from e

    if row is None:
        return False

    # Stored format: base64(salt)$base64(sha256(salt||password))
    if not isinstance(row[0], (str, bytes, bytearray)):
        raise ValueError()
    stored = row[0].decode('utf-8') if isinstance(row[0], (bytes, bytearray)) else row[0]
    if '$' not in stored:
        raise ValueError()
    salt_b64, digest_b64 = stored.split('$', 1)
    try:
        salt = base64.b64decode(salt_b64)
        digest = base64.b64decode(digest_b64)
    except Exception as e:
        raise ValueError() from e

    mac = hashlib.sha256(salt + bytes(password)).digest()
    return hmac.compare_digest(mac, digest)

