def xpath_query(request):
    '''
    Get the `xpath` value from the GET request,
    get the 'xml' value from the GET request,
    construct and parse the xml payload,
    return the result of the XPath query "/tag[@id={}]" format from the parsed xml
    '''
    if request is None or not hasattr(request, 'GET'):
        raise TypeError()
    if not isinstance(request.GET, dict):
        raise TypeError()
    if 'xpath' not in request.GET or 'xml' not in request.GET:
        raise ValueError()

    value = request.GET['xpath']
    xml_text = request.GET['xml']
    if not isinstance(value, str) or not isinstance(xml_text, str):
        raise TypeError()

    # Only allow simple IDs to prevent XPath injection.
    if not re.fullmatch(r"[A-Za-z0-9_-]{1,32}", value):
        raise ValueError()

    if 'etree' not in globals() or not hasattr(etree, 'parse'):
        raise RuntimeError()

