import os
import hashlib


def storePassword(userName, Password):
    '''
    Hash the password and update the database with username and hashed password by invoking the updateUserLogin() method
    '''
    if not isinstance(userName, str):
        raise TypeError()
    if not isinstance(Password, (bytes, bytearray)):
        raise TypeError()

    salt = os.urandom(16)
    dk = hashlib.pbkdf2_hmac('sha256', bytes(Password), salt, 100000)
    record = {'salt': salt, 'hash': dk, 'algo': 'pbkdf2_hmac_sha256'}

    if 'updateUserLogin' not in globals() or not callable(updateUserLogin):
        raise RuntimeError()

    return updateUserLogin(userName, record)

