            result[i * 4 + 1] = (m_state[i] >> 16) & 0xFF;
            result[i * 4 + 2] = (m_state[i] >> 8) & 0xFF;
            result[i * 4 + 3] = m_state[i] & 0xFF;
        }
        return result;
    }
